const body = $json.body || $json;
const websiteInput = body.website_id || body.source_url || body.url;
const question = body.question;

if (!websiteInput) {
  throw new Error("Missing website_id, source_url, or url in request body.");
}

if (!question) {
  throw new Error("Missing question in request body.");
}

function normalizeWebsiteId(value) {
  const raw = String(value).trim().replace(/^["']|["']$/g, '');

  try {
    const parsed = new URL(/^https?:\/\//i.test(raw) ? raw : `https://${raw}`);
    if (parsed.hostname && parsed.hostname.includes('.')) {
      return parsed.hostname
        .replace(/^www\./i, '')
        .replace(/[^a-zA-Z0-9]+/g, '-')
        .replace(/^-+|-+$/g, '')
        .toLowerCase();
    }
  } catch (error) {}

  return raw
    .replace(/^https?:\/\//i, '')
    .replace(/^www\./i, '')
    .split(/[/?#]/)[0]
    .replace(/[^a-zA-Z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .toLowerCase();
}

return [{
  json: {
    website_id: normalizeWebsiteId(websiteInput),
    question: String(question).trim()
  }
}];
